if(  isBlank(leaseworks__MSN_E__c) , 
/* Other */
if(isBlank(leaseworks__ESN__c),
 if(isBlank(text(leaseworks__Asset_Type__c) ),'NA',Text( leaseworks__Asset_Type__c ))
,/* engine*/'ESN ' &  leaseworks__ESN__c  )
,
/* MSN present*/
if( leaseworks__Y_Hidden_Aircraft_Engine__c =='Aircraft','MSN ' & leaseworks__MSN_E__c,if(leaseworks__Y_Hidden_Aircraft_Engine__c=='Engine','ESN ' & leaseworks__MSN_E__c,'SN' & leaseworks__MSN_E__c))
& ', ' & if(isBlank(leaseworks__YoM__c) ,'NA',leaseworks__YoM__c)  
& ', ' & text(leaseworks__Asset_Type__c )
)

& ', ' &  leaseworks__Deal_Summary_c__c
